// Script Continued Below
// KT - Hotfix 2
//var taskerNM = new TaskerDisplayValueConfiguration();

// v2.5.13 | 08.08.2020 | STRY0076605:  Sequential Review
var insertTaskerHelper = new TaskerHelpers();
var initialState = insertTaskerHelper.getInitialState(current);
current.state = initialState;


// STRY0051139 - allow customer to use the script associated with this to set key values in the system
// ships with the defalut setting current.taskernumber = current.u_task_tree.u_shared_task_label + '-' + current.getDisplayValue('primary_assignee');
//var taskerNM = new TaskerDisplayValueConfiguration();
//current.taskernumber = taskerNM.setTaskerNumber(current);

// STRY0072379
var bDateOk = true;
var now = new GlideDateTime();
if(gs.getProperty('x_153465_discovert.Suspense Dates and Expected Start Dates must be in the future') == 'true'){
	if(now > current.suspense_date && current.suspense_date != ""){
		gs.addErrorMessage('The suspense date must be in the future.');
		bDateOk = false;
	}
}
if(bDateOk)
	current.insert();
